const e=[{id:2,name:"Ar. Athirah Yen",role:"LAM AG/A 678, BSc. Arch (Hons) Taylor‘s, M. Arch UM, LAM/RIBA PART II",image:"People/athirah.jpeg"},{id:3,name:"haziqah ngasri",role:"Dipl. Fine Art, Bsc. Arch (Hons) UITM, LAM Part I",image:"People/haziqah.jpeg"},{id:4,name:"Hester Chang",role:"BSc. Arch (Hons) Taylor’s, LAM Part I",image:"People/hester.jpeg"},{id:5,name:"shu herng",role:"BA Arch. (Hons) ESALA, RIBA Part I",image:"People/shu.jpeg"},{id:6,name:"brandon ngiau",role:"Bsc. Arch (Hons) Taylor‘s, LAM Part I",image:"People/brandon.jpeg"},{id:7,name:"REVATHY SIVA",role:"B. Arch (Hons) UMK, LAM Part I",image:"People/revathy.jpeg"},{id:8,name:"daphne wee",role:"B Arch. (Hons) SEGi, LAM Part I",image:"People/daphne.jpeg"},{id:9,name:"yusof hafiz",role:"BSc. Arch (Hons), MSc. Applied Arch. & Design QUEENS, RIBA/ARB/LAM Part II",image:"People/yusof.jpeg"},{id:10,name:"VIKTOR ZEIDLER LIM",role:"BSc. Arch (Hons) Taylor’s, LAM Part I",image:"People/viktor.jpeg"}],a=[{name:"Huat LIM",role:" Managing Director",image:"People/huatsolo.jpeg",bio:["Huat Lim studied at the Architectural Association in London from 1981 to 1984. He has been a member of the Architects Registration Board and the Royal Institute of British Architects since 1987. Among his tutors at the AA were Peter Cook, Christine Hawley, Peter Salter, Ron Herron, Rodrigo Pérez de Arce and Gordon Pask, probably his most influential mentor.","Huat taught briefly at the Bartlett London, with Sir Peter Cook and David Dunster. Huat LIM has been employed to work on very large and complex buildings, a career spanning over 22 years, principally at Lord Foster London Stansted Airport, the Nimes Mediateque Museum, HKSB HQ at Canary Wharf, the Masterplan for King Cross Redevelopment, and later at Imagination Limited Jubilee Line Extension for London with the late Ron Herron of Archigram fame.","In Asia, Huat worked on GDP Asia Broadcasting Centre and their NTV7 Radio and Television Studios. Huat was also engaged to work with design teams to win TRHYeang Singapore National Library Competition and LDY entry for the Xian International Airport Competition."]},{name:"Susanne ZEIDLER",role:"Executive Director",image:"People/susannesolo.jpeg",bio:["Susanne ZEIDLER hails from Frankfurt and studied art history before her postgraduate term at the Staedle Schule under the tutorship of Professor Peter COOK, and later at the Bartlett School of Architecture, London. Susanne moved to Malaysia in 1992, and now lives in Kuala Lumpur and is Executive Director and Senior Partner at zlgdesign.","Her most significant contribution to zlgdesign is the BOH Visitor Centre which has since won wide public recognition. Susanne is no less of an architect than she is a designer, having delivered most of the interior design projects for the firm, namely the I-Zen, Puncak Dana and the MK Land Interiors and Show Unit designs.","Her training in London after a stint in Germany at the Frankfurtschule under the tutorship of Sir Peter Cook of Archigram fame, has given her an interesting edge through her very broad but yet distinctive cultural style to her work at zlgdesign. Susanne was instrumental in the delivery of the BOH Visitor Centre."]}],t=[{name:"sc shekar",title:"photographer",image:"/general/partners/scshekar_solo.avif"},{name:"gareth richards",title:"editor, copyrighter, public speaker",image:"/general/partners/gareth_solo_1.avif"},{name:"the one academy",title:"",image:"/general/partners/toa_landscape.avif"},{name:"taylors university",title:"",image:"/general/partners/tu_landscape.avif"},{name:"damien yow",title:"entrepreneur, civil engineer"},{name:"nike baetzner",title:"researcher, historian"},{name:"justus pysall",title:"architect"},{name:"suburbia books",title:"publisher"},{name:"zeidler&lim",title:"publisher, foundation"},{name:"renny booth",title:"architect"},{name:"viktor zeidler",title:"graphic designer"},{name:"zora gabrovsek",title:"gallerist, film producer"},{name:"brandon chee",title:"ecologist"}];export{t as j,a as k,e as t};
